const row = $input.first().json;
const keys = Object.keys(row);
const find = (partial) => {
  const k = keys.find(k => k.toLowerCase().includes(partial.toLowerCase()));
  return k ? row[k] || null : null;
};

return [{
  json: {
    first_name:       row['First name'] || null,
    last_name:        row['Last name'] || null,
    age:              row['And what is your age?'] || null,
    email:            find('email') || null,
    phone:            find('Phone') || null,
    location:         find('country and city') || null,
    employed:         find('currently employed') === 'TRUE',
    profession:       find('profession') || null,
    monthly_salary:   find('monthly salary') || null,
    calendly_url:     find('Schedule your free') || null,
    utm_source:       row['utm_source'] || null,
    utm_medium:       row['utm_medium'] || null,
    utm_campaign:     row['utm_campaign'] || null,
    utm_content:      row['utm_content'] || null,
    speciality:       find('speciality') || null,
    years_experience: find('years of experience') || null,
    additional_info:  find('anything else') || null,
    family_medicine:  find('Family Medicine') || null,
    client_id:        row['client_id'] || null,
    traffic_source:   row['traffic_source'] || null,
    is_new:           row['new'] || null,
    training_country: find('training in your speciality') || null,
    submitted_at:     row['Submitted At'] || null,
    token:            row['Token'] || null,
    channel:          row['Channel'] || null
  }
}];
